mapper.select:
SELECT s.student_no, s.name, s.age, s.gender, s.grade_level, s.class_name, p.gpa, p.grade_class, GREATEST(s.updated_at, COALESCE(p.updated_at, s.updated_at)) AS update_time FROM student s LEFT JOIN student_performance p ON p.student_id = s.id WHERE s.deleted = 0 AND ( s.name LIKE CONCAT('%', #{keyword}, '%')
OR s.student_no = #{studentNo}
)

SELECT
s.student_no,
s.name,
s.age,
s.gender,
s.grade_level,
s.class_name,
p.gpa,
p.grade_class,
GREATEST(s.updated_at, COALESCE(p.updated_at, s.updated_at)) AS update_time
FROM student s
LEFT JOIN student_performance p ON p.student_id = s.id
WHERE s.deleted = 0

    AND s.grade_level = #{gradeLevel}


    AND s.gender = #{gender}


    AND s.class_name IN

        #{className}



    AND (


            OR (

                p.gpa >= #{minGpa}



                    AND

                p.gpa <= #{maxGpa}

            )


            OR p.grade_class = #{gradeClass}


    )
